package com.cuzssp.campussecondhandtradingplatform_backend.mapper;import com.cuzssp.campussecondhandtradingplatform_backend.common.entity.Product;import org.apache.ibatis.annotations.*;import java.util.List;@Mapperpublic interface ProductMapper {    @Select("SELECT * FROM product WHERE id = #{id}")    Product selectById(@Param("id") Long id);    @Select("SELECT * FROM product WHERE id = #{id} FOR UPDATE")    Product selectByIdForUpdate(@Param("id") Long id);    @Select("SELECT * FROM product")    List<Product> selectAll();    @Select("SELECT * FROM product " +            "WHERE user_id = #{userId} " +            "ORDER BY created_at DESC")    List<Product> selectByUserId(@Param("userId") Long userId);    @Select("SELECT COUNT(*) FROM product WHERE status = 1")    int countActive();    @Select("SELECT COUNT(*) FROM product")    int countAll();    @Select("SELECT COUNT(*) FROM product WHERE category_id = #{categoryId}")    int countByCategoryId(@Param("categoryId") Long categoryId);    @Insert("INSERT INTO product (user_id, category_id, title, description, " +            "price, original_price, `condition`, campus, status, view_count, created_at, updated_at) " +            "VALUES (#{userId}, #{categoryId}, #{title}, #{description}, " +            "#{price}, #{originalPrice}, #{condition}, #{campus}, #{status}, " +            "#{viewCount}, #{createdAt}, #{updatedAt})")    @Options(useGeneratedKeys = true, keyProperty = "id")    int insert(Product product);    @Update("UPDATE product SET view_count = view_count + 1 WHERE id = #{id}")    int incrementViewCount(@Param("id") Long id);    @Update("UPDATE product " +            "SET title=#{title}, description=#{description}, price=#{price}, " +            "original_price=#{originalPrice}, `condition`=#{condition}, campus=#{campus}, " +            "category_id=#{categoryId}, status=#{status}, view_count=#{viewCount}, updated_at=#{updatedAt} " +            "WHERE id=#{id}")    int updateById(Product product);    @Delete("DELETE FROM product WHERE id = #{id}")    int deleteById(@Param("id") Long id);    List<Product> selectByUserIdWithLimit(@Param("userId") Long userId,                                          @Param("offset") Integer offset,                                          @Param("batchSize") Integer batchSize);    List<Product> selectByKeywordOrCategoryOrCampusOrStatus(@Param("keyword") String keyword,                                                            @Param("categoryId") Long categoryId,                                                            @Param("campus") String campus,                                                            @Param("status") Integer status);}